                "(function() { var e = document.getElementById('typeans'); return e ? e.value : ''; })()"
            ) { value ->
                // The returned value is a JSON string (quoted), so we need to remove quotes
                typeAnswer!!.input = value?.trim('"') ?: ""
                displayCardAnswerContinue()
            }
        } else {
            displayCardAnswerContinue()
        }
    }

    /**
     * Continues displaying the card answer after the typed input has been captured.
     * This is called either directly from displayCardAnswer() when not using input tag,
     * or from the JavaScript callback when using input tag.
     */
    private fun displayCardAnswerContinue() {
        val answerContent = htmlGenerator!!.generateHtml(getColUnsafe, currentCard!!, SingleCardSide.BACK)
        automaticAnswer.onDisplayAnswer()
        launchCatchingTask {
            if (!automaticAnswerShouldWaitForAudio()) {
                automaticAnswer.scheduleAutomaticDisplayQuestion()
            }
        }
        updateCard(answerContent)
        displayAnswerBottomBar()
    }"}

