1308→    open fun displayCardAnswer() {
1309→        // #7294 Required in case the animation end action does not fire:
1310→        actualHideEaseButtons()
1311→        Timber.d("displayCardAnswer()")
1312→        mediaErrorHandler.onCardSideChange()
1313→        backButtonPressedToReturn = false
1314→
1315→        // prevent answering (by e.g. gestures) before card is loaded
1316→        if (currentCard == null) {
1317→            return
1318→        }
1319→
1320→        // TODO needs testing: changing a card's model without flipping it back to the front
1321→        //  (such as editing a card, then editing the card template)
1322→        typeAnswer!!.updateInfo(getColUnsafe, currentCard!!, resources)
1323→
1324→        // Explicitly hide the soft keyboard. It *should* be hiding itself automatically,
1325→        // but sometimes failed to do so (e.g. if an OnKeyListener is attached).
1326→        if (typeAnswer!!.validForEditText()) {
1327→            val inputMethodManager = getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager
1328→            inputMethodManager.hideSoftInputFromWindow(answerField!!.windowToken, 0)
1329→        }
1330→        displayAnswer = true
1331→        answerField!!.visibility = View.GONE
1332→        // Clean up the user answer and the correct answer
1333→        if (!typeAnswer!!.useInputTag) {
1334→            typeAnswer!!.input = answerField!!.text.toString()
1335→        }
1336→        isSelecting = false
1337→        // When using input tag in WebView, get the typed value directly from the input element
1338→        // before generating the answer HTML. This ensures the comparison is shown correctly
1339→        // even if the blur event hasn't been processed yet.
1340→        if (typeAnswer!!.useInputTag && typeAnswer!!.correct != null && webView != null) {
1341→            webView!!.evaluateJavascript(
1342→                "(function() { var e = document.getElementById('typeans'); return e ? e.value : ''; })()"
1343→            ) { value ->
1344→                // The returned value is a JSON-encoded string (e.g., "hello" with quotes).
1345→                // Parse it as JSON to properly handle escaped characters.
1346→                typeAnswer!!.input = try {
1347→                    if (value.isNullOrEmpty() || value == "null") {
1348→                        ""
1349→                    } else {
1350→                        org.json.JSONArray("[$value]").optString(0, "")
1351→                    }
1352→                } catch (e: Exception) {
1353→                    Timber.w(e, "Failed to parse typed answer from WebView")
1354→                    ""
1355→                }
1356→                displayCardAnswerContinue()
1357→            }
1358→        } else {
1359→            displayCardAnswerContinue()
1360→        }
1361→    }
